from sympy import isprime

def is_multiply_prime(a):
    for i in range(2, 100):
        if a % i == 0 and isprime(i):
            j = a // i
            for k in range(i + 1, 100):
                if j % k == 0 and isprime(k):
                    m = j // k
                    if m > k and isprime(m):
                        return True
    return False

